import dataList from "../../nav-list/nav-list.json";

const NavBar: React.FC = () => {

  const dropDownDiscovery = dataList.find(item => item.title === "Discovery")?.items;
  const dropDownAbout = dataList.find(item => item.title === "About")?.items;


  return (
    <>
      <div className={styles.nav__bar}>
        <NavButton text="Discovery" handleClick={toggleDiscoveryMenu} />
        <NavButton text="About" handleClick={toggleAboutMenu} />
        <NavButton text="Contact us" href="/contact" isLink={true} />
      </div>
      {/* <MegaMenu show={isDiscoveryMenuVisible} />
      <MegaMenu show={isAboutMenuVisible} /> */}
    </>
  );
};

export default NavBar;



